import{c as e,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"MemGPT: Towards LLMs as Operating Systems","description":"","frontmatter":{"title":"MemGPT: Towards LLMs as Operating Systems","authors":"Charles Packer et al.","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2310.08560-memgpt-arxiv.md","filePath":"research/agent-harness/references/2310.08560-memgpt-arxiv.md","lastUpdated":1779796674000}'),s={name:"research/agent-harness/references/2310.08560-memgpt-arxiv.md"};function l(i,a,o,h,d,g){return t(),r("div",null,[...a[0]||(a[0]=[n(`<h1 id="memgpt-towards-llms-as-operating-systems" tabindex="-1">MemGPT: Towards LLMs as Operating Systems <a class="header-anchor" href="#memgpt-towards-llms-as-operating-systems" aria-label="Permalink to &quot;MemGPT: Towards LLMs as Operating Systems&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2310.08560" target="_blank" rel="noreferrer">https://arxiv.org/abs/2310.08560</a></li><li><strong>發表</strong>: 2023（更新至 2024-02）</li><li><strong>作者</strong>: Charles Packer et al.</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority A — Long-running agent 記憶管理的基礎架構；虛擬 context 管理的開創性論文</li></ul><hr><h2 id="核心類比-llm-作為操作系統" tabindex="-1">核心類比：LLM 作為操作系統 <a class="header-anchor" href="#核心類比-llm-作為操作系統" aria-label="Permalink to &quot;核心類比：LLM 作為操作系統&quot;">​</a></h2><p>傳統 OS 管理有限的 RAM（快速但有限）+ 無限的磁盤（慢但無限）。</p><p>MemGPT 將同樣的原理應用到 LLM：</p><table tabindex="0"><thead><tr><th>OS 概念</th><th>MemGPT 對應</th></tr></thead><tbody><tr><td>RAM（快速、有限）</td><td>Context Window（main context）</td></tr><tr><td>磁碟（慢、無限）</td><td>External Memory（recall + archive）</td></tr><tr><td>虛擬記憶體</td><td>Virtual Context Management</td></tr><tr><td>頁面置換</td><td>動態 context 移入/移出</td></tr></tbody></table><hr><h2 id="三層記憶架構" tabindex="-1">三層記憶架構 <a class="header-anchor" href="#三層記憶架構" aria-label="Permalink to &quot;三層記憶架構&quot;">​</a></h2><h3 id="layer-1-main-memory-主記憶體" tabindex="-1">Layer 1：Main Memory（主記憶體） <a class="header-anchor" href="#layer-1-main-memory-主記憶體" aria-label="Permalink to &quot;Layer 1：Main Memory（主記憶體）&quot;">​</a></h3><ul><li>存放內容：當前對話、working notes、最近事件</li><li>對應：LLM 的 context window</li><li>限制：有限 token 預算</li></ul><h3 id="layer-2-recall-storage-回憶資料庫" tabindex="-1">Layer 2：Recall Storage（回憶資料庫） <a class="header-anchor" href="#layer-2-recall-storage-回憶資料庫" aria-label="Permalink to &quot;Layer 2：Recall Storage（回憶資料庫）&quot;">​</a></h3><ul><li>存放內容：完整的過去對話歷史</li><li>存取方式：語義搜索（embedding）+ 時間戳</li><li>讀/寫：agent 可以主動查詢</li></ul><h3 id="layer-3-archival-storage-檔案存儲" tabindex="-1">Layer 3：Archival Storage（檔案存儲） <a class="header-anchor" href="#layer-3-archival-storage-檔案存儲" aria-label="Permalink to &quot;Layer 3：Archival Storage（檔案存儲）&quot;">​</a></h3><ul><li>存放內容：長期知識、文件、筆記</li><li>存取方式：向量索引（FAISS 等）</li><li>讀/寫：結構化知識庫</li></ul><hr><h2 id="控制流設計-interrupts-機制" tabindex="-1">控制流設計：Interrupts 機制 <a class="header-anchor" href="#控制流設計-interrupts-機制" aria-label="Permalink to &quot;控制流設計：Interrupts 機制&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LLM 決定動作 → 發送 interrupt 訊號 →</span></span>
<span class="line"><span>  - LOAD_FROM_RECALL: 從回憶 DB 載入特定記憶</span></span>
<span class="line"><span>  - SEARCH_ARCHIVAL: 搜索長期存儲</span></span>
<span class="line"><span>  - PUSH_TO_ARCHIVAL: 存入長期記憶</span></span>
<span class="line"><span>  - PAUSE_HEARTBEAT: 告知系統需要更多時間</span></span></code></pre></div><p>這讓 LLM 自己管理記憶的讀寫，而不是靠外部系統強制執行。</p><hr><h2 id="核心應用場景" tabindex="-1">核心應用場景 <a class="header-anchor" href="#核心應用場景" aria-label="Permalink to &quot;核心應用場景&quot;">​</a></h2><ol><li><strong>分析超長文件</strong>：比 context window 大 10x+ 的文件，按需載入相關片段</li><li><strong>長期對話 agent</strong>：記住用戶的偏好、歷史決策、長期目標</li><li><strong>多 session 任務</strong>：agent 能「記得」上個 session 發生了什麼</li></ol><hr><h2 id="對-harness-engineering-的影響" tabindex="-1">對 Harness Engineering 的影響 <a class="header-anchor" href="#對-harness-engineering-的影響" aria-label="Permalink to &quot;對 Harness Engineering 的影響&quot;">​</a></h2><h3 id="洞見-1-context-管理是-harness-的核心責任-不是-llm-的責任" tabindex="-1">洞見 #1：Context 管理是 harness 的核心責任，不是 LLM 的責任 <a class="header-anchor" href="#洞見-1-context-管理是-harness-的核心責任-不是-llm-的責任" aria-label="Permalink to &quot;洞見 #1：Context 管理是 harness 的核心責任，不是 LLM 的責任&quot;">​</a></h3><p>MemGPT 明確把「決定什麼留在 context、什麼存到外部」作為系統責任，而不是讓 LLM 自己決定。</p><h3 id="洞見-2-讀寫記憶的-api-設計至關重要" tabindex="-1">洞見 #2：讀寫記憶的 API 設計至關重要 <a class="header-anchor" href="#洞見-2-讀寫記憶的-api-設計至關重要" aria-label="Permalink to &quot;洞見 #2：讀寫記憶的 API 設計至關重要&quot;">​</a></h3><p>Interrupts 的設計方式（LLM 主動發出信號而非被動接收）讓 agent 對記憶有更多控制權。這啟發了後來 harness 設計中的「agent-initiated context management」。</p><h3 id="洞見-3-三層記憶不是可選優化-是長期-agent-的必要架構" tabindex="-1">洞見 #3：三層記憶不是可選優化，是長期 agent 的必要架構 <a class="header-anchor" href="#洞見-3-三層記憶不是可選優化-是長期-agent-的必要架構" aria-label="Permalink to &quot;洞見 #3：三層記憶不是可選優化，是長期 agent 的必要架構&quot;">​</a></h3><p>任何需要跨 session 工作的 agent 都需要類似的分層記憶架構。</p><hr><h2 id="後續發展" tabindex="-1">後續發展 <a class="header-anchor" href="#後續發展" aria-label="Permalink to &quot;後續發展&quot;">​</a></h2><ul><li><strong>Letta</strong>（MemGPT 商業化版）：成熟的 stateful agent 平台</li><li><strong>A-Mem</strong>（2502.12110）：加入 Zettelkasten 動態連結機制</li><li><strong>Mem0</strong>（2504.19413）：企業級記憶管理，支持個性化</li></ul><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv: <a href="https://arxiv.org/abs/2310.08560" target="_blank" rel="noreferrer">https://arxiv.org/abs/2310.08560</a></li><li>MemGPT Research: <a href="https://research.memgpt.ai/" target="_blank" rel="noreferrer">https://research.memgpt.ai/</a></li><li>Letta（商業化）: <a href="https://www.letta.com/" target="_blank" rel="noreferrer">https://www.letta.com/</a></li></ul>`,35)])])}const m=e(s,[["render",l]]);export{p as __pageData,m as default};
